solution_code:
#include <array>
#include <iostream>
#include <iomanip>

int main() {
    std::array<int, 5> nums {};
    for (int i = 0; i < 5; ++i) {
        std::cin >> nums[i];
    }

    int sum = 0;
    for (int x : nums) {
        sum += x;
    }

    double avg = static_cast<double>(sum) / 5.0;
    std::cout << "Sum: " << sum << '\n';
    std::cout << "Average: " << std::fixed << std::setprecision(1) << avg << '\n';
    return 0;
}

